14	const AUTH_TOKEN_LIFETIME_TO_REFRESH = 60;
15	const REFRESH_TOKEN_EXPIRATION_TIME = 24 * 60 * 60 * 1000;
16	
17	export const authConfig: NextAuthOptions = {
18	  secret: ENV.NEXTAUTH_SECRET,
19	  providers: [
20	    CredentialsProvider({
21	      id: "credentials",
22	      name: "Credentials",
23	      credentials: {
24	        email: { label: "Email", type: "text" },
25	        password: { label: "Password", type: "password" },
26	      },
27	      authorize: async (credentials): Promise<null | User> => {
28	        if (!(credentials?.email && credentials?.password)) return null;
29	
30	        try {
31	          const response = await signIn({
32	            email: credentials.email,
33	            password: credentials.password,
34	          });
35	
36	          if (
37	            response.status === "CHALLENGE" &&
38	            response.challengeName === "NEW_PASSWORD_REQUIRED"
39	          ) {
40	            return {
41	              id: "",
42	              email: credentials.email,
43	              accessToken: "",
44	              refreshToken: "",
45	              idToken: "",
46	              isTemporaryPassword: true,
47	              tempPasswordSession: response.session,
48	            };
49	          }
50	
51	          if (response.status === "SUCCESS") {
52	            const { payload } = response;
53	
54	            const profile = await getProfileWithToken(payload.accessToken);
55	
56	            return {
57	              id: profile.id,
58	              email: profile.email,
59	              accessToken: payload.accessToken,
60	              refreshToken: payload.refreshToken,
61	              idToken: payload.idToken,
62	              refreshTokenExpiresAt: Date.now() + REFRESH_TOKEN_EXPIRATION_TIME,
63	              profile,
64	            };
65	          }
66	
67	          console.error("Error signing in:", response);
68	
69	          return null;
70	        } catch (e) {
71	          console.error("Error signing in:", e);
72	          return null;
73	        }
74	      },
75	    }),
76	    CredentialsProvider({
77	      id: "google-oauth",
78	      name: "Google",
79	      credentials: {
80	        idToken: { label: "ID Token", type: "text" },
81	      },
82	      authorize: async (credentials): Promise<null | User> => {
83	        if (!credentials?.idToken) return null;
84	
85	        try {
86	          const response = await oauthGoogle({ idToken: credentials.idToken });
87	
88	          if (response.status === "SUCCESS") {
89	            const { payload } = response;
90	
91	            // Decode Google id_token to get basic user info as fallback
92	            const googlePayload = JSON.parse(
93	              Buffer.from(
94	                credentials.idToken.split(".")[1].replace(/-/g, "+").replace(/_/g, "/"),
95	                "base64",
96	              ).toString(),
97	            ) as { sub?: string; email?: string };
98	
99	            let profile;
100	            try {
101	              profile = await getProfileWithToken(payload.accessToken);
102	              console.log("[Google OAuth] profile fetched:", profile?.id, profile?.roles);
103	            } catch (profileError) {
104	              console.error("[Google OAuth] getProfileWithToken failed:", profileError);
105	            }
106	
107	            return {
108	              id: profile?.id ?? googlePayload.sub ?? "",
109	              email: profile?.email ?? googlePayload.email ?? "",
110	              accessToken: payload.accessToken,
111	              refreshToken: payload.refreshToken,
112	              idToken: payload.idToken || "",
113	              refreshTokenExpiresAt: Date.now() + REFRESH_TOKEN_EXPIRATION_TIME,
114	              profile,
115	            };
116	          }
117	
118	          return null;
119	        } catch (error) {
120	          console.error("Google OAuth error:", error);
121	          return null;
122	        }
123	      },
124	    }),
125	  ],
126	
127	  callbacks: {
128	    async jwt({ token, user, account, trigger, session }): Promise<JWT> {
129	      const isManualUpdate = trigger === "update" && session;
130	
131	      if (isManualUpdate) {
132	        return {
133	          ...token,
134	          ...session,
135	        };
136	      }
137	
138	      if (account && user) {
139	        token.id = user.id;
140	        token.email = user.email;
141	        token.accessToken = user.accessToken;
142	        token.refreshToken = user.refreshToken;
143	        token.idToken = user.idToken;
144	        token.refreshTokenExpiresAt = user.refreshTokenExpiresAt;
145	        token.session = user.session;
146	        token.profile = user.profile;
147	        token.isTemporaryPassword = user.isTemporaryPassword;
148	        token.tempPasswordSession = user.tempPasswordSession;
149	        token.provider = account.provider;
150	      }
151	
152	      const expiresIn = calculateExpiresIn(token.accessToken);
153	
154	      if (expiresIn < AUTH_TOKEN_LIFETIME_TO_REFRESH && token.refreshToken) {
155	        const newAccessToken = await refreshAccessToken(
156	          token.refreshToken,
157	          token.accessToken,
158	        );
159	
160	        if (newAccessToken) {
161	          token.accessToken = newAccessToken.accessToken;
162	          token.refreshToken = newAccessToken.refreshToken;
163	          token.idToken = newAccessToken.idToken;
164	        }
165	      }
166	
167	      return token;
168	    },
169	
170	    async session({ session, token }) {
171	      if (token) {
172	        session.accessToken = token.accessToken;
173	        session.refreshToken = token.refreshToken;
174	        session.idToken = token.idToken;
175	        session.refreshTokenExpiresAt = token.refreshTokenExpiresAt;
176	        session.session = token.session;
177	        session.isTemporaryPassword = token.isTemporaryPassword;
178	        session.tempPasswordSession = token.tempPasswordSession;
179	        session.provider = token.provider;
180	        session.user = {
181	          id: token.id,
182	          email: token.email,
183	          profile: token.profile,
184	        };
185	      }
186	
187	      return session;
188	    },
189	
190	    async signIn() {
191	      return true;
192	    },
193	  },
194	
195	  pages: {
196	    signIn: APP_ROUTES.AUTH.SIGN_IN,
197	  },
198	
199	  session: {
200	    strategy: "jwt",
201	    maxAge: 30 * 24 * 60 * 60,
202	  },
203	};
