205	async function refreshAccessToken(
206	  refreshTokenValue: string,
207	  accessTokenValue: string,
208	) {
209	  try {
210	    const url = `${ENV.NEXT_PUBLIC_APP_API_URL}${API_ROUTES.AUTH.REFRESH_TOKEN}`;
211	    const response = await fetch(url, {
212	      method: "POST",
213	      headers: {
214	        "Content-Type": "application/json",
215	      },
216	      body: JSON.stringify({
217	        refreshToken: refreshTokenValue,
218	        accessToken: accessTokenValue,
219	      }),
220	    });
221	
222	    if (!response.ok) {
223	      throw new Error("Failed to refresh access token");
224	    }
225	
226	    const result = (await response.json()) as RefreshTokenResponse;
227	
228	    return {
229	      accessToken: result.accessToken,
230	      refreshToken: result.refreshToken,
231	      idToken: result.idToken,
232	    };
233	  } catch (error) {
234	    console.error("Failed to refresh access token:", error);
235	    return null;
236	  }
237	}
